nodes/delete-middle-node.text:
import { AfterViewInit, Component, OnDestroy, viewChild } from '@angular/core';
import { DiagramCanvasComponent } from '@grafloria/angular';
import { SnapController } from '@grafloria/renderer';
import { markReady } from '../demo-ready';

/** Delete B out of A→B→C and the chain HEALS: its two edges cascade away and a
 *  fresh A→C bridge is drawn. Select a node, press Delete/Backspace — the heal
 *  reads getIncomers × getOutgoers, removes the node, then commits one real,
 *  undoable bridge link through the shipped SnapController command. */
@Component({
  standalone: true,
  imports: [DiagramCanvasComponent],
  templateUrl: './delete-middle-node.component.html',
})
export class DeleteMiddleNodeComponent implements AfterViewInit, OnDestroy {
  canvas = viewChild.required(DiagramCanvasComponent);
  nodes = [
    { id: 'a', position: { x: 60,  y: 120 }, size: { width: 160, height: 80 }, label: 'A' },
    { id: 'b', position: { x: 340, y: 120 }, size: { width: 160, height: 80 }, label: 'B (middle)' },
    { id: 'c', position: { x: 620, y: 120 }, size: { width: 160, height: 80 }, label: 'C' },
  ];
  edges = [
    { id: 'ab', source: 'a', target: 'b' },
    { id: 'bc', source: 'b', target: 'c' },
  ];
  private keyHandler?: (e: KeyboardEvent) => void;

  ngAfterViewInit() {
    const engine = this.canvas().activeEngine();
    const m = engine?.getDiagram();
    if (engine && m) {
      const snap = new SnapController();
      const eng = engine as any;
      const model = m as any;
      const healDelete = async (id: string) => {
        const links = model.getLinks();
        const incomers = [...new Set(links.filter((l: any) => l.targetNodeId === id).map((l: any) => l.sourceNodeId))] as string[];
        const outgoers = [...new Set(links.filter((l: any) => l.sourceNodeId === id).map((l: any) => l.targetNodeId))] as string[];
        await eng.removeNode(id);
        for (const s of incomers) for (const t of outgoers) {
          if (s === t) continue;
          const sn = model.getNode(s), tn = model.getNode(t);
          if (!sn || !tn) continue;
          if (model.getLinks().some((l: any) => l.sourceNodeId === s && l.targetNodeId === t)) continue;
          const candidate = {
            sourcePort: sn.getPortBySide('right') ?? sn.getPorts()[0],
            targetPort: tn.getPortBySide('left') ?? tn.getPorts()[0],
            sourceNodeId: s, targetNodeId: t, distance: 0,
          };
          eng.commandManager.execute(snap.buildProximityLinkCommand(candidate));
        }
      };
      this.keyHandler = (e: KeyboardEvent) => {
        if (e.key !== 'Delete' && e.key !== 'Backspace') return;
        const sel = model.getSelectedNodes ? model.getSelectedNodes() : [];
        if (!sel.length) return;
        e.preventDefault();
        e.stopImmediatePropagation();
        (async () => { for (const n of sel) await healDelete(n.id); })();
      };
      window.addEventListener('keydown', this.keyHandler, true);
    }
    markReady();
  }

  ngOnDestroy() {
    if (this.keyHandler) window.removeEventListener('keydown', this.keyHandler, true);
  }
}

nodes/easy-connect.text:
import { AfterViewInit, Component, OnDestroy, viewChild } from '@angular/core';
import { DiagramCanvasComponent } from '@grafloria/angular';
import { registerTool, SnapController } from '@grafloria/renderer';
import { markReady } from '../demo-ready';

/** Easy Connect: the WHOLE node body is a connection handle. Press anywhere on
 *  one node, release anywhere on another, and they wire up — wired through the
 *  public registerTool seam, committing with the shipped link command. */
@Component({
  standalone: true,
  imports: [DiagramCanvasComponent],
  templateUrl: './easy-connect.component.html',
})
export class EasyConnectComponent implements AfterViewInit, OnDestroy {
  canvas = viewChild.required(DiagramCanvasComponent);
  nodes = [
    { id: 'a', position: { x: 100, y: 150 }, size: { width: 200, height: 120 }, label: 'A · press anywhere' },
    { id: 'b', position: { x: 560, y: 150 }, size: { width: 200, height: 120 }, label: 'B · release anywhere' },
  ];
  edges = [];
  private dispose?: () => void;

  ngAfterViewInit() {
    const engine = this.canvas().activeEngine();
    const model = engine?.getDiagram() as any;
    if (engine && model) {
      const eng = engine as any;
      const snap = new SnapController();
      let src: any = null;
      this.dispose = registerTool({
        id: 'demo-easy-connect',
        priority: 10,
        hitTest: (_e: any, hit: any) => !!hit.node,
        onPointerDown: (_e: any, hit: any) => { src = hit.node; },
        onPointerUp: (e: any) => {
          if (!src) return;
          const tgt = model.getNodeAtPosition(e.world.x, e.world.y);
          if (tgt && tgt.id !== src.id) {
            const candidate = {
              sourcePort: src.getPortBySide('right') ?? src.getPorts()[0],
              targetPort: tgt.getPortBySide('left') ?? tgt.getPorts()[0],
              sourceNodeId: src.id, targetNodeId: tgt.id, distance: 0,
            };
            eng.commandManager.execute(snap.buildProximityLinkCommand(candidate));
          }
          src = null;
        },
        onCancel: () => { src = null; },
      } as any) as any;
    }
    markReady();
  }

  ngOnDestroy() { this.dispose?.(); }
}

nodes/intersections.text:
import { AfterViewInit, Component, viewChild } from '@angular/core';
import { DiagramCanvasComponent } from '@grafloria/angular';
import { markReady } from '../demo-ready';

/** Drag a node and every node it overlaps lights up red, live. The overlap set
 *  is recomputed on every node:moved from the model's spatial index; the moved
 *  node itself stays unpainted (React Flow parity). */
const HILITE = { type: 'rect', fill: '#fecaca', stroke: '#dc2626' };
const rectOf = (n: any) => ({ x: n.position.x, y: n.position.y, width: n.size.width, height: n.size.height });

@Component({
  standalone: true,
  imports: [DiagramCanvasComponent],
  templateUrl: './intersections.component.html',
})
export class IntersectionsComponent implements AfterViewInit {
  canvas = viewChild.required(DiagramCanvasComponent);
  nodes = [
    { id: 'a', position: { x: 120, y: 140 }, size: { width: 180, height: 110 }, label: 'A · drag me' },
    { id: 'b', position: { x: 460, y: 140 }, size: { width: 180, height: 110 }, label: 'B' },
    { id: 'c', position: { x: 800, y: 140 }, size: { width: 180, height: 110 }, label: 'C' },
    { id: 's', position: { x: 150, y: 430 }, size: { width: 60, height: 60 }, label: 'S' },
  ];
  edges = [];

  ngAfterViewInit() {
    const model = this.canvas().activeEngine()?.getDiagram() as any;
    if (model) {
      const hits = (id: string): string[] => model
        .getVisibleNodes(rectOf(model.getNode(id)))
        .filter((o: any) => o.id !== id)
        .map((o: any) => o.id);
      const relight = (movedId: string) => {
        const moved = model.getNode(movedId);
        if (!moved) return;
        const lit = hits(movedId);
        for (const n of model.getNodes()) {
          const want = lit.includes(n.id);
          const has = n.getMetadata('shape') === HILITE;
          if (want && !has) n.setMetadata('shape', HILITE);
          else if (!want && has) n.setMetadata('shape', undefined);
        }
      };
