import { AfterViewInit, Component, OnDestroy, viewChild } from '@angular/core';
import { DiagramCanvasComponent } from '@grafloria/angular';
import { registerTool } from '@grafloria/renderer';
import { markReady } from '../demo-ready';

/** A node carries a rotation the renderer bakes into rotate(θ, cx, cy). Spin it
 *  with a real pointer drag wired through the public registerTool seam. */
@Component({
  standalone: true,
  imports: [DiagramCanvasComponent],
  templateUrl: './rotatable-node.component.html',
})
export class RotatableNodeComponent implements AfterViewInit, OnDestroy {
  canvas = viewChild.required(DiagramCanvasComponent);
  nodes = [{ id: 'n', position: { x: 360, y: 150 }, size: { width: 200, height: 120 }, label: 'spin me' }];
  edges = [];
  private dispose?: () => void;

  ngAfterViewInit() {
    const engine = this.canvas().activeEngine();
    if (engine) {
      let grab: any = null;
      const center = (node: any) => ({
        x: node.position.x + node.size.width / 2,
        y: node.position.y + node.size.height / 2,
      });
      this.dispose = registerTool({
        id: 'demo-rotate',
        priority: 10,
        hitTest: (_e: any, hit: any) => !!hit.node,
        onPointerDown: (e: any, hit: any) => {
          const c = center(hit.node);
          grab = { node: hit.node, cx: c.x, cy: c.y, a0: Math.atan2(e.world.y - c.y, e.world.x - c.x), r0: hit.node.rotation };
        },
        onPointerMove: (e: any) => {
          if (!grab) return;
          const a = Math.atan2(e.world.y - grab.cy, e.world.x - grab.cx);
          grab.node.setRotation(grab.r0 + (a - grab.a0) * 180 / Math.PI);
        },
        onPointerUp: () => { grab = null; },
      } as any) as any;
    }
    markReady();
  }

  ngOnDestroy() { this.dispose?.(); }
}

nodes/stress-test.text:
import { AfterViewInit, Component } from '@angular/core';
import { DiagramCanvasComponent } from '@grafloria/angular';
import { markReady } from '../demo-ready';

/** A 900-node mesh (30×30, each wired to its right + down neighbour). Viewport
 *  culling keeps only the visible slice in the DOM; one layout call snaps all
 *  900 into a clean layered diamond. */
const R = 30, C = 30;
const nid = (r: number, c: number) => 'n' + (r * C + c);

function buildNodes() {
  const nodes = [];
  for (let r = 0; r < R; r++)
    for (let c = 0; c < C; c++)
      nodes.push({ id: nid(r, c), position: { x: c * 120, y: r * 80 }, size: { width: 92, height: 46 }, label: '' + (r * C + c) });
  return nodes;
}
function buildEdges() {
  const edges = [];
  for (let r = 0; r < R; r++)
    for (let c = 0; c < C; c++) {
      if (c + 1 < C) edges.push({ id: 'h' + r + '_' + c, source: nid(r, c), target: nid(r, c + 1) });
      if (r + 1 < R) edges.push({ id: 'v' + r + '_' + c, source: nid(r, c), target: nid(r + 1, c) });
    }
  return edges;
}

@Component({
  standalone: true,
  imports: [DiagramCanvasComponent],
  templateUrl: './stress-test.component.html',
})
export class StressTestComponent implements AfterViewInit {
  layout = { name: 'layered', options: { direction: 'TB', nodeSpacing: 20, rankSpacing: 52 } };
  nodes = buildNodes();
  edges = buildEdges();
  ngAfterViewInit() { markReady(); }
}

