});

const uml = umlDiagram({
  classes: [
    { id: 'Repo', name: 'Repository', position: { x: 460, y: 400 }, height: 240,
      attributes: Array.from({ length: 16 }, (_, i) => `- field${i + 1}: string`),
      methods: Array.from({ length: 10 }, (_, i) => `+ op${i + 1}(): void`) },
