import { AfterViewInit, Component, ElementRef, viewChild } from '@angular/core';
import { DiagramCanvasComponent } from '@grafloria/angular';
import { markReady } from '../demo-ready';

/** Level-of-detail: the detail the renderer draws follows the zoom. Zoom in for
 *  full labels; zoom out and the renderer sheds detail. The readout reports the
 *  zoom and how much label text reaches the DOM — genuinely different renders. */
@Component({
  standalone: true,
  imports: [DiagramCanvasComponent],
  templateUrl: './contextual-zoom.component.html',
})
export class ContextualZoomComponent implements AfterViewInit {
  canvas = viewChild.required(DiagramCanvasComponent);
  readout = viewChild.required<ElementRef<HTMLElement>>('readout');
  host = viewChild.required<ElementRef<HTMLElement>>('host');
  nodes: any[] = Array.from({ length: 12 }, (_, i) => ({
    id: `n${i}`, position: { x: (i % 4) * 200, y: Math.floor(i / 4) * 140 },
    size: { width: 150, height: 70 }, label: `Node ${i}`,
  }));
  edges: any[] = Array.from({ length: 11 }, (_, i) => ({ id: `e${i}`, source: `n${i}`, target: `n${i + 1}`, type: 'direct' }));

  ngAfterViewInit() {
    this.canvas().fitToContent(40);
    this.setZoom(1.5);
    markReady();
  }

  setZoom(z: number) {
    const vp = this.canvas().viewportController();
    vp?.setZoom(z);
    const texts = this.host().nativeElement.querySelectorAll('svg text').length;
    const el = this.readout()?.nativeElement;
    if (el) el.textContent = `zoom ${z}×  →  ${texts} text nodes in the DOM`;
  }
}

interaction/copy-paste.text:
import { AfterViewInit, Component, ElementRef, viewChild } from '@angular/core';
import { DiagramCanvasComponent } from '@grafloria/angular';
import { markReady } from '../demo-ready';

/** Copy a node to the engine clipboard, then paste independent copies — each
 *  gets its own id and position, and mutating one leaves the others untouched.
 *  ⌘C / ⌘V drive the same engine.copy() / engine.paste() path. */
@Component({
  standalone: true,
  imports: [DiagramCanvasComponent],
  templateUrl: './copy-paste.component.html',
})
export class CopyPasteComponent implements AfterViewInit {
  canvas = viewChild.required(DiagramCanvasComponent);
  readout = viewChild.required<ElementRef<HTMLElement>>('readout');
  nodes: any[] = [
    { id: 'orig', position: { x: 120, y: 120 }, size: { width: 130, height: 50 }, label: 'Original' },
  ];
  edges: any[] = [];
  private key?: (e: KeyboardEvent) => void;

  async ngAfterViewInit() {
    const engine = this.canvas().activeEngine() as any;
    const model = engine?.getDiagram();
    const report = (m: string) => { const el = this.readout()?.nativeElement; if (el) el.textContent = m; };
    if (!engine || !model) { markReady(); return; }

    // Demonstrate the round trip on load: select, copy, paste one independent copy.
    engine.selectNodes(['orig']);
    await engine.copy();
    await engine.paste({ offset: { x: 60, y: 60 } });
    report(`copied Original; ${model.getNodes().length} nodes — ⌘C then ⌘V to make more`);

    this.key = (e: KeyboardEvent) => {
      if (!(e.metaKey || e.ctrlKey)) return;
      if (e.key === 'c') { engine.copy(); }
      if (e.key === 'v') {
        e.preventDefault();
        engine.paste({}).then(() => report(`${model.getNodes().length} nodes — each paste cascades to a new spot`));
      }
    };
    window.addEventListener('keydown', this.key);
    markReady();
  }
}

interaction/drag-and-drop.text:
import { AfterViewInit, Component, ElementRef, viewChild } from '@angular/core';
import { DiagramCanvasComponent } from '@grafloria/angular';
import { markReady } from '../demo-ready';

/** Drag a chip out of the palette and drop it on the canvas: a node is created
 *  AT THE DROP POINT in world space (through the live viewport), so it lands
 *  under the cursor even after the camera has panned/zoomed. */
@Component({
  standalone: true,
  imports: [DiagramCanvasComponent],
  templateUrl: './drag-and-drop.component.html',
})
export class DragAndDropComponent implements AfterViewInit {
  canvas = viewChild.required(DiagramCanvasComponent);
  host = viewChild.required<ElementRef<HTMLElement>>('host');
  readout = viewChild.required<ElementRef<HTMLElement>>('readout');
  nodes: any[] = [];
  edges: any[] = [];

  async ngAfterViewInit() {
    const engine = this.canvas().activeEngine() as any;
    const model = engine?.getDiagram();
    const host = this.host().nativeElement;
    const vp = this.canvas().viewportController();
    if (!engine || !model || !vp) { markReady(); return; }

    const report = () => { const el = this.readout()?.nativeElement; if (el) el.textContent = `${model.getNodes().length} nodes`; };
    const dropAt = async (kind: string, clientX: number, clientY: number) => {
      const w = vp.clientToWorld(clientX, clientY, host.getBoundingClientRect());
      const node = await engine.addNode({ type: 'rect', position: { x: w.x - 55, y: w.y - 22 }, size: { width: 110, height: 44 } });
      node.data = { kind };
      node.setMetadata('label', kind);
      report();
      return node;
    };

    // Seed two dropped nodes so the result of the gesture is visible on load.
    const r = host.getBoundingClientRect();
    await dropAt('filter', r.left + r.width * 0.4, r.top + r.height * 0.4);
    await dropAt('sink', r.left + r.width * 0.6, r.top + r.height * 0.6);

    // Live HTML5 drag-and-drop for a human visitor.
    let dragKind: string | null = null;
    for (const chip of Array.from(host.ownerDocument.querySelectorAll<HTMLElement>('.chip'))) {
      chip.addEventListener('dragstart', () => { dragKind = chip.dataset['kind'] ?? null; });
    }
    host.addEventListener('dragover', (e) => e.preventDefault());
    host.addEventListener('drop', (e) => { e.preventDefault(); if (dragKind) dropAt(dragKind, e.clientX, e.clientY); });
    markReady();
  }
}

