import { AfterViewInit, Component, viewChild } from '@angular/core';
import { DiagramCanvasComponent } from '@grafloria/angular';
import { markReady } from '../demo-ready';

/** Move the container, the contents follow: drag a subflow's frame and every
 *  member travels with it as one undoable step, while a non-member stays put.
 *  The only host wiring is setInteractionConfig({ enableGroupDrag: true }); the
 *  engine's live drag path translates members and frame together. */
@Component({
  standalone: true,
  imports: [DiagramCanvasComponent],
  templateUrl: './parent-move.component.html',
})
export class ParentMoveComponent implements AfterViewInit {
  canvas = viewChild.required(DiagramCanvasComponent);
  nodes: any[] = [
    { id: 'm1', position: { x: 400, y: 200 }, size: { width: 100, height: 50 }, label: 'stage 1' },
    { id: 'm2', position: { x: 560, y: 220 }, size: { width: 100, height: 50 }, label: 'stage 2' },
    { id: 'outside', position: { x: 120, y: 500 }, size: { width: 100, height: 50 }, label: 'outside' },
  ];
  edges: any[] = [{ id: 'e1', source: 'm1', target: 'm2' }];

  async ngAfterViewInit() {
    const engine = this.canvas().activeEngine() as any;
    if (engine) {
      engine.setInteractionConfig({ enableGroupDrag: true });
      const g = await engine.addGroup({ name: 'Pipeline' });
      g.setFrame({ x: 370, y: 180, width: 320, height: 170 });
      await engine.addToGroup(g.id, 'm1');
      await engine.addToGroup(g.id, 'm2');
    }
    markReady();
  }
}

interaction/preventing-cycles.text:
import { AfterViewInit, Component, OnDestroy, viewChild } from '@angular/core';
import { DiagramCanvasComponent } from '@grafloria/angular';
import { registerConnectionValidator, clearConnectionValidators } from '@grafloria/renderer';
import { markReady } from '../demo-ready';

/** A DAG that stays acyclic: a validator walks the live directed edges and
 *  refuses any connection whose target can already reach its source, so
 *  a→b→c→d can never close into a loop. */
@Component({
  standalone: true,
  imports: [DiagramCanvasComponent],
  templateUrl: './preventing-cycles.component.html',
})
export class PreventingCyclesComponent implements AfterViewInit, OnDestroy {
  canvas = viewChild.required(DiagramCanvasComponent);
  nodes: any[] = ['a', 'b', 'c', 'd'].map((id, i) => ({
    id, position: { x: 60 + i * 170, y: 120 }, size: { width: 110, height: 46 }, label: id.toUpperCase(),
  }));
  edges: any[] = [
    { id: 'ab', source: 'a', target: 'b' },
    { id: 'bc', source: 'b', target: 'c' },
    { id: 'cd', source: 'c', target: 'd' },
  ];
  private dispose?: () => void;

  ngAfterViewInit() {
    const model = this.canvas().activeEngine()?.getDiagram() as any;
    const reaches = (fromId: string, toId: string) => {
      const nodeOf = (portId: string, cached: string) => model.getNodeByPortId(portId)?.id ?? cached;
      const seen = new Set<string>(); const stack = [fromId];
      while (stack.length) {
        const cur = stack.pop()!;
        if (cur === toId) return true;
        if (seen.has(cur)) continue;
        seen.add(cur);
        for (const link of model.getLinks()) {
          if (nodeOf(link.sourcePortId, link.sourceNodeId) === cur) stack.push(nodeOf(link.targetPortId, link.targetNodeId));
        }
      }
      return false;
    };
    clearConnectionValidators();
    this.dispose = registerConnectionValidator(({ sourceNode, targetNode }: any) => {
      if (!sourceNode || !targetNode || !model) return true;
      if (reaches(targetNode.id, sourceNode.id)) return 'Refused: would create a cycle';
      return true;
    }) as any;
    this.canvas().activeEngine()?.setInteractionConfig({ portVisibility: 'always' as never });
    markReady();
  }

  ngOnDestroy() { this.dispose?.(); clearConnectionValidators(); }
}

interaction/proximity-connect-live.text:
import { AfterViewInit, Component, viewChild } from '@angular/core';
import { DiagramCanvasComponent } from '@grafloria/angular';
import { markReady } from '../demo-ready';

/** Proximity connect wired into the ENGINE: drag a node next to another and the
 *  engine's own drag path proposes AND commits the wire — the page only sets
 *  enableProximityConnect. The auto-created link is a single undoable step. */
@Component({
  standalone: true,
  imports: [DiagramCanvasComponent],
  templateUrl: './proximity-connect-live.component.html',
})
export class ProximityConnectLiveComponent implements AfterViewInit {
  canvas = viewChild.required(DiagramCanvasComponent);
  nodes: any[] = [
    { id: 'a', position: { x: 150, y: 150 }, size: { width: 150, height: 80 }, label: 'drag me →' },
    { id: 'b', position: { x: 600, y: 150 }, size: { width: 150, height: 80 }, label: 'B' },
  ];
  edges: any[] = [];

  ngAfterViewInit() {
    this.canvas().activeEngine()?.setInteractionConfig({ enableProximityConnect: true } as never);
    markReady();
  }
}

interaction/touch-device.text:
import { AfterViewInit, Component } from '@angular/core';
import { DiagramCanvasComponent } from '@grafloria/angular';
import { markReady } from '../demo-ready';

/** Real finger input: one finger pans, one finger on a node drags it, a tap
 *  selects, and two fingers pinch-zoom — all through the same touch pipeline a
 *  phone uses. touch-action:none keeps the browser from eating the gesture. */
@Component({
  standalone: true,
  imports: [DiagramCanvasComponent],
